SELECT /* base.ec.od :: OdOrderDiscnt :: selectList */ d.* , ste.site_nm AS site_nm , ord.member_nm AS order_nm , cpn.coupon_nm AS coupon_nm , cd_odt.code_label AS discnt_type_cd_nm FROM od_order_discnt d LEFT JOIN sy_site ste ON ste.site_id = d.site_id LEFT JOIN od_order ord ON ord.order_id = d.order_id LEFT JOIN pm_coupon cpn ON cpn.coupon_id = d.coupon_id LEFT JOIN sy_code cd_odt ON cd_odt.code_grp = 'ORDER_DISCNT_TYPE' AND cd_odt.code_value = d.discnt_type_cd
ORDER BY d.order_discnt_id ASC ORDER BY d.order_discnt_id DESC ORDER BY d.reg_date ASC ORDER BY d.reg_date DESC ORDER BY d.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

